import org.gradle.api.DefaultTask
import org.gradle.api.file.ConfigurableFileCollection
import org.gradle.api.file.DirectoryProperty
import org.gradle.api.tasks.Classpath
import org.gradle.api.tasks.Input
import org.gradle.api.tasks.OutputDirectory
import org.gradle.api.tasks.TaskAction
import org.gradle.process.ExecOperations
import javax.inject.Inject

/*
 * This file was generated by the Gradle 'init' task.
 */

plugins {
    id("buildlogic.server-conventions")
}

@CacheableTask
abstract class GenerateLiquibaseScriptsTask : DefaultTask() {
    @get:Inject
    abstract val execOperations: ExecOperations

    @get:Classpath
    abstract val runtimeClasspath: ConfigurableFileCollection

    @get:OutputDirectory
    abstract val outputDir: DirectoryProperty

    @get:Input
    abstract val projectVersion: org.gradle.api.provider.Property<String>

    @TaskAction
    fun generate() {
        val destination = outputDir.get().asFile
        destination.mkdirs()
        execOperations.javaexec {
            classpath = runtimeClasspath
            mainClass.set("io.camunda.db.rdbms.LiquibaseScriptGenerator")
            args(destination.absolutePath, projectVersion.get())
        }
    }
}

dependencies {
    api(libs.org.liquibase.liquibase.core)
    api(libs.org.springframework.spring.core)
    api(libs.org.apache.commons.commons.lang3)
}

val generatedLiquibaseDir = layout.buildDirectory.dir("generated/liquibase")

val generateScriptsFromLiquibase by tasks.registering(GenerateLiquibaseScriptsTask::class) {
    group = "build"
    description = "Generate SQL scripts from Liquibase changelogs"
    dependsOn(tasks.named("classes"))
    runtimeClasspath.from(sourceSets["main"].runtimeClasspath)
    outputDir.set(generatedLiquibaseDir)
    projectVersion.set(project.version.toString())
}

tasks.named<Jar>("jar") {
    dependsOn(generateScriptsFromLiquibase)
    from(generatedLiquibaseDir)
}

description = "Camunda Secondary DB - RDBMS - Schema"
